INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published) VALUES

('DALL-E 3', 'dall-e-3', 'OpenAI''s most capable image generation model', 'DALL-E 3 creates highly detailed and accurate images from text descriptions, with improved understanding of nuance and context. Available via ChatGPT Plus and OpenAI API.', 'https://openai.com/dall-e-3', 'freemium', '[{"plan":"ChatGPT Free","price":0,"period":"month","features":["Limited generations"]},{"plan":"ChatGPT Plus","price":20,"period":"month","features":["Priority access","HD generations","Unlimited standard"]}]', 'beginner', true, '{web,api}', '{"Text-to-image generation","HD image output","Inpainting","Prompt rewriting","DALL-E API access","Safety filters"}', '{"ChatGPT","OpenAI API","Microsoft Designer","Bing Image Creator"}', 'https://platform.openai.com/docs/guides/images', true),

('Adobe Firefly', 'adobe-firefly', 'AI image and creative content generation built for creators', 'Adobe Firefly is a family of creative generative AI models that generates images, text effects, and vectors trained on licensed content. Deeply integrated into Adobe Creative Cloud apps.', 'https://firefly.adobe.com', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["25 generative credits/month"]},{"plan":"Creative Cloud","price":54.99,"period":"month","features":["100 generative credits/month","All CC apps"]}]', 'beginner', true, '{web,api}', '{"Text-to-image","Generative Fill","Text effects","Generative Recolor","Structure Reference","Style Reference"}', '{"Adobe Photoshop","Adobe Illustrator","Adobe Express","Adobe Premiere Pro"}', 'https://developer.adobe.com/firefly-services/', true),

('Leonardo.ai', 'leonardo-ai', 'AI image generation platform for game assets and creative content', 'Leonardo.ai specializes in generating consistent, high-quality game assets, concept art, and character designs. Offers fine-tuning, custom models, and a large community of trained models.', 'https://leonardo.ai', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["150 tokens/day","Basic features"]},{"plan":"Apprentice","price":12,"period":"month","features":["8500 tokens/month","Priority generation"]},{"plan":"Artisan","price":30,"period":"month","features":["25000 tokens/month","Unlimited relaxed"]}]', 'intermediate', true, '{web,api}', '{"Text-to-image","Image-to-image","Inpainting","ControlNet","Motion (video)","Custom model training","Canvas editor"}', '{"Discord","Zapier","API integrations"}', 'https://docs.leonardo.ai', true),

('Ideogram', 'ideogram', 'AI image generator that actually gets text right', 'Ideogram excels at generating images with accurate, readable text embedded in them — a notoriously difficult challenge for AI art generators. Great for logos, posters, and graphics with typography.', 'https://ideogram.ai', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["10 slow generations/day"]},{"plan":"Basic","price":7,"period":"month","features":["400 priority generations/month"]},{"plan":"Plus","price":16,"period":"month","features":["1000 priority generations/month"]}]', 'beginner', false, '{web}', '{"Text-in-image generation","Magic prompt","Remix","Describe (image to prompt)","Canvas","Reframe"}', '{}', 'https://about.ideogram.ai', true),

('Playground AI', 'playground-ai', 'Free-to-use AI image creator with powerful editing tools', 'Playground AI lets you create stunning images with a generous free tier. Supports multiple AI models (Stable Diffusion, DALL-E, playground-v2) with real-time editing, filters, and a social community.', 'https://playground.com', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["500 images/day","Playground v2 model"]},{"plan":"Pro","price":15,"period":"month","features":["Unlimited standard images","Priority queue"]}]', 'beginner', true, '{web}', '{"Multi-model support","Canvas editor","Image editing","Filters","Outpainting","Community gallery"}', '{"Stable Diffusion models","DALL-E"}', 'https://playground.com/blog', true),

('Getimg.ai', 'getimg-ai', 'AI image generation suite with 60+ models', 'Getimg.ai provides access to 60+ AI models for image generation, editing, and enhancement. Features face swap, text-to-image, image-to-image, and a real-time canvas editor for professionals.', 'https://getimg.ai', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["100 images/month"]},{"plan":"Basic","price":12,"period":"month","features":["3000 images/month"]},{"plan":"Starter","price":29,"period":"month","features":["12000 images/month"]}]', 'intermediate', true, '{web,api}', '{"60+ AI models","Text-to-image","Image-to-image","Inpainting","Outpainting","Face swap","Upscaling","API access"}', '{}', 'https://docs.getimg.ai', true),

('Bing Image Creator', 'bing-image-creator', 'Free AI image generation powered by DALL-E 3', 'Microsoft''s free image generation tool powered by DALL-E 3, accessible directly in Bing and Edge browser. Generates high-quality images from text descriptions with no sign-up required for basic use.', 'https://www.bing.com/images/create', 'free', '[{"plan":"Free","price":0,"period":"month","features":["Boosted generations with Microsoft account","Standard generations unlimited"]}]', 'beginner', false, '{web}', '{"DALL-E 3 powered","Free to use","Edge integration","Image History"}', '{"Microsoft Edge","Bing Chat","Copilot"}', 'https://www.bing.com/images/create', true),

('NightCafe', 'nightcafe', 'AI art generator with multiple creation modes', 'NightCafe is an AI art generator with a vibrant community, daily challenges, and support for multiple algorithms including Stable Diffusion, DALL-E, and SDXL. Features a credit system and social features.', 'https://creator.nightcafe.studio', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["5 free credits/day"]},{"plan":"AI Hobbyist","price":7.99,"period":"month","features":["100 credits/month"]},{"plan":"AI Enthusiast","price":15.99,"period":"month","features":["250 credits/month"]}]', 'beginner', false, '{web,mobile}', '{"Multiple AI algorithms","Text-to-image","Style transfer","Daily challenges","Community gallery","NFT minting"}', '{}', 'https://nightcafe.studio', true)

