('Sora', 'sora', 'OpenAI''s text-to-video model for realistic video generation', 'Sora generates realistic and imaginative video scenes from text instructions, creating videos up to a minute long while maintaining visual quality and adhering to the user''s prompt.', 'https://sora.com', 'paid', '[{"plan":"ChatGPT Plus","price":20,"period":"month","features":["50 priority generations","Relaxed mode"]},{"plan":"ChatGPT Pro","price":200,"period":"month","features":["Unlimited relaxed","500 priority","1080p"]}]', 'beginner', false, '{web}', '{"Text-to-video","Image-to-video","Video-to-video","Storyboard","Remix","Blend","Loop","Cut","Re-cut"}', '{"ChatGPT"}', 'https://sora.com', true),

('Pika', 'pika', 'AI video creation and editing for everyone', 'Pika transforms text and images into cinematic videos with precise control over motion, camera angles, and style. Features sound effects generation and easy-to-use controls for non-technical users.', 'https://pika.art', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["150 credits/month"]},{"plan":"Standard","price":8,"period":"month","features":["700 credits/month","HD downloads"]},{"plan":"Pro","price":28,"period":"month","features":["2000 credits/month","4K","Priority"]}]', 'beginner', false, '{web,mobile}', '{"Text-to-video","Image-to-video","Video-to-video","Sound effects","Lip sync","Pikaffects","Camera controls"}', '{}', 'https://pika.art', true),

('Luma Dream Machine', 'luma-dream-machine', 'Photorealistic AI video generation from text and images', 'Luma AI''s Dream Machine generates high-quality, realistic videos from text and images. Known for exceptionally realistic physics, motion, and consistency in character appearance across frames.', 'https://lumalabs.ai/dream-machine', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["30 generations/month"]},{"plan":"Standard","price":29.99,"period":"month","features":["120 generations/month","720p"]},{"plan":"Plus","price":99.99,"period":"month","features":["400 generations/month","1080p"]}]', 'beginner', true, '{web,api}', '{"Text-to-video","Image-to-video","Keyframe control","Camera motion","Extend video","Photorealistic output"}', '{}', 'https://lumalabs.ai/api', true),

('Kling AI', 'kling-ai', 'Kuaishou''s powerful text-to-video and image-to-video model', 'Kling AI by Kuaishou generates high-quality 1080p videos up to 3 minutes long from text or images. Features 5-second and 10-second video generation with realistic motion and high consistency.', 'https://klingai.com', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["66 credits/month"]},{"plan":"Standard","price":9.99,"period":"month","features":["660 credits/month"]},{"plan":"Pro","price":29.99,"period":"month","features":["3000 credits/month"]}]', 'beginner', true, '{web,api}', '{"Text-to-video","Image-to-video","Face swap","Lip sync","Virtual try-on","1080p output","5 and 10 second videos"}', '{}', 'https://klingai.com/api', true),

('HeyGen', 'heygen', 'AI video generation with realistic avatars and voice cloning', 'HeyGen creates professional videos using AI avatars that speak in 175+ languages. Ideal for marketing, training, and product demos — upload a script, choose an avatar, and export a polished video.', 'https://heygen.com', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["3 video credits","1 min/video"]},{"plan":"Creator","price":29,"period":"month","features":["15 video credits","5 min/video"]},{"plan":"Team","price":89,"period":"month","features":["Unlimited seats","30 credits"]}]', 'beginner', true, '{web,api}', '{"AI avatars","Voice cloning","Script-to-video","Talking photo","Video translation","Custom avatar","175+ languages"}', '{"Zapier","HubSpot","Salesforce"}', 'https://docs.heygen.com', true),

('Synthesia', 'synthesia', 'Create professional AI videos from text in minutes', 'Synthesia turns text scripts into professional videos featuring AI presenters in 130+ languages. Used by 50,000+ businesses for training videos, marketing, and internal communications without cameras.', 'https://synthesia.io', 'paid', '[{"plan":"Starter","price":22,"period":"month","features":["3 video exports/month","120+ AI avatars"]},{"plan":"Creator","price":67,"period":"month","features":["10 video exports/month","Custom AI avatar"]},{"plan":"Enterprise","price":0,"period":"month","features":["Custom","API access"]}]', 'beginner', true, '{web,api}', '{"130+ languages","180+ AI avatars","Custom avatar","Screen recording","Templates","Brand kit","Collaboration"}', '{"PowerPoint","Google Slides","Canva","SharePoint","LMS integrations"}', 'https://help.synthesia.io', true),

('Invideo AI', 'invideo-ai', 'Turn ideas and scripts into polished videos with AI', 'InVideo AI converts text prompts or scripts into fully edited videos with stock footage, voiceover, music, and captions. Ideal for YouTube, social media, and marketing content at scale.', 'https://invideo.io', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["10 minutes export/week","Watermark"]},{"plan":"Plus","price":25,"period":"month","features":["50 AI videos/month","No watermark"]},{"plan":"Max","price":60,"period":"month","features":["200 AI videos/month","GPT-4o"]}]', 'beginner', false, '{web}', '{"Text-to-video","AI script writer","Stock footage","AI voiceover","Auto subtitles","Templates","Brand presets"}', '{"YouTube","iStock","Shutterstock","Storyblocks"}', 'https://invideo.io/help', true),

('Captions', 'captions', 'AI-powered video creation and editing app', 'Captions is an AI video app that auto-generates captions, removes filler words, enhances eye contact, and creates short-form content from long videos. Popular among creators for polished social media content.', 'https://captions.ai', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["Limited exports"]},{"plan":"Pro","price":16.99,"period":"month","features":["Unlimited exports","Eye contact correction","Green screen"]}]', 'beginner', false, '{mobile,web}', '{"Auto captions","Filler word removal","Eye contact correction","AI video creation","Background removal","Translation","AI script"}', '{"TikTok","Instagram","YouTube"}', 'https://captions.ai', true),

('Opus Clip', 'opus-clip', 'Repurpose long videos into viral short clips with AI', 'Opus Clip uses AI to analyze long-form videos (YouTube, podcasts, webinars) and automatically extracts the most engaging moments into short clips ready for TikTok, Reels, and Shorts.', 'https://opus.pro', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["60 upload minutes/month"]},{"plan":"Starter","price":9,"period":"month","features":["150 upload minutes/month"]},{"plan":"Pro","price":29,"period":"month","features":["Unlimited clipping","Brand kit"]}]', 'beginner', false, '{web}', '{"Auto clip generation","Viral score","Auto captions","Face tracking","Speaker detection","Brand templates","B-roll"}', '{"YouTube","Zoom","Google Drive","Dropbox","TikTok"}', 'https://opus.pro', true)

