INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published) VALUES

('Warp', 'warp', 'AI-powered terminal for developers', 'Warp is a modern terminal with AI built in. Ask questions in natural language to get commands, debug errors, and understand shell output. Features intelligent autocomplete, command search, and team sharing.', 'https://warp.dev', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["Unlimited local usage","AI completions"]},{"plan":"Team","price":22,"period":"month","features":["Shared workflows","Analytics","SSO"]}]', 'intermediate', false, '{desktop}', '{"AI command generation","Natural language shell","Intelligent autocomplete","Warp AI","Block-based input","Command history search","Team notebooks"}', '{"GitHub","VS Code","Fish","Zsh","Bash"}', 'https://docs.warp.dev', true),

('Continue', 'continue', 'Open-source AI code assistant for VS Code and JetBrains', 'Continue is an open-source autopilot for software development that integrates with VS Code and JetBrains. Connect any LLM, add custom context, and build personalized coding workflows with full control.', 'https://continue.dev', 'free', '[{"plan":"Free","price":0,"period":"month","features":["Open source","Bring your own model","Unlimited"]}]', 'intermediate', true, '{desktop,api}', '{"Any LLM support","Tab autocomplete","Chat interface","Custom context","Codebase indexing","Slash commands","Model switching","Privacy mode"}', '{"VS Code","JetBrains","OpenAI","Anthropic","Ollama","Mistral","Gemini"}', 'https://docs.continue.dev', true),

('Pieces for Developers', 'pieces-for-developers', 'AI-powered code snippet manager and developer assistant', 'Pieces is an on-device AI toolkit that captures, enriches, and resurfaces code snippets with full context. Integrates across IDEs and browsers to save, search, and reuse code with AI assistance.', 'https://pieces.app', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["Personal use","On-device AI","Unlimited snippets"]},{"plan":"Teams","price":0,"period":"month","features":["Shared snippets","Team features"]}]', 'intermediate', false, '{desktop,web}', '{"Code snippet capture","Context enrichment","On-device AI","Cross-IDE sync","Code search","Live context","Copilot chat","OCR snippets"}', '{"VS Code","JetBrains","Chrome","GitHub","Jira","Confluence","Slack"}', 'https://docs.pieces.app', true),

('Aider', 'aider', 'AI pair programming in your terminal', 'Aider is an open-source AI coding assistant that runs in your terminal and lets you pair program with Claude or GPT-4. Makes code changes across multiple files, runs tests, and commits with meaningful messages.', 'https://aider.chat', 'free', '[{"plan":"Free","price":0,"period":"month","features":["Open source","Bring your own API key"]}]', 'advanced', true, '{desktop}', '{"Multi-file editing","Git integration","Auto commit","Test running","Map repository","Voice coding","Browser support","Any LLM"}', '{"Git","OpenAI","Anthropic","Groq","Ollama","DeepSeek"}', 'https://aider.chat/docs', true),

('Sweep AI', 'sweep-ai', 'AI software engineer that fixes bugs and builds features', 'Sweep is a GitHub-native AI developer that converts issues into pull requests. Describe a bug or feature in a GitHub issue, and Sweep reads your codebase, writes the code, tests it, and opens a PR.', 'https://sweep.dev', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["5 issues/month","Public repos"]},{"plan":"Pro","price":240,"period":"month","features":["Unlimited issues","Private repos","Priority"]}]', 'intermediate', false, '{web}', '{"Issue-to-PR automation","Codebase understanding","Test writing","Code review","Multi-file changes","GitHub Actions integration"}', '{"GitHub","Linear"}', 'https://docs.sweep.dev', true),

('CodiumAI', 'codiumai', 'AI for writing meaningful tests automatically', 'CodiumAI (now Qodo) analyzes your code and generates comprehensive test suites automatically. Identifies edge cases, suggests improvements, and ensures your code actually works as intended.', 'https://codium.ai', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["Individual use","VS Code plugin"]},{"plan":"Teams","price":19,"period":"month","features":["Team features","PR agent","Analytics"]}]', 'intermediate', false, '{desktop,web}', '{"Automated test generation","Edge case detection","Code integrity","PR agent","Test suggestions","Multi-language","VS Code + JetBrains"}', '{"VS Code","JetBrains","GitHub","GitLab","Bitbucket"}', 'https://docs.codium.ai', true)

ON CONFLICT (slug) DO NOTHING;

-- ─── PRODUCTIVITY (MORE) ─────────────────────────────────────

INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published) VALUES

('Mem', 'mem', 'Self-organizing AI workspace for notes and knowledge', 'Mem is an AI-powered notes app that automatically organizes your information, surfaces relevant notes when you need them, and lets you chat with your entire knowledge base. No folders, no tags needed.', 'https://mem.ai', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["Limited AI","500 notes"]},{"plan":"Pro","price":14.99,"period":"month","features":["Unlimited notes","AI chat","Smart search"]}]', 'beginner', false, '{web,mobile,desktop}', '{"AI organization","Smart search","Chat with notes","Related notes","Capture everywhere","Calendar integration","Team spaces","Offline mode"}', '{"Slack","Gmail","Google Calendar","Zoom","Notion"}', 'https://help.mem.ai', true),

('Fireflies.ai', 'fireflies-ai', 'AI meeting assistant for transcription and summaries', 'Fireflies.ai records, transcribes, summarizes, and searches all your meetings. Integrates with every major video platform and syncs insights to your CRM, Slack, and project management tools automatically.', 'https://fireflies.ai', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["800 min transcription storage","3 AI summaries"]},{"plan":"Pro","price":18,"period":"month","features":["Unlimited transcription","Unlimited AI summaries"]},{"plan":"Business","price":29,"period":"month","features":["Conversation intelligence","Analytics"]}]', 'beginner', false, '{web,mobile}', '{"Meeting transcription","AI summaries","Action items","Sentiment analysis","Speaker ID","Smart search","Meeting playlists","CRM sync"}', '{"Zoom","Google Meet","MS Teams","Webex","HubSpot","Salesforce","Slack","Notion"}', 'https://guide.fireflies.ai', true),

('Superhuman', 'superhuman', 'AI-powered email client built for speed', 'Superhuman is the fastest email client ever made, with AI writing assistance, instant search, follow-up reminders, and keyboard-first design. Claims users save 4+ hours per week on email.', 'https://superhuman.com', 'paid', '[{"plan":"Starter","price":30,"period":"month","features":["AI writing","Snippets","Read statuses"]},{"plan":"Business","price":40,"period":"month","features":["Team features","Analytics","Priority support"]}]', 'intermediate', false, '{web,desktop,mobile}', '{"AI email drafting","AI triage","Keyboard shortcuts","Split inbox","Snippets","Follow-up reminders","Read statuses","Instant search","Undo send"}', '{"Gmail","Outlook","Google Calendar","Zoom","Superhuman API"}', 'https://help.superhuman.com', true),

('Notion Calendar', 'notion-calendar', 'AI-powered calendar that connects to Notion', 'Notion Calendar (formerly Cron) combines a powerful calendar experience with Notion''s connected workspace. Schedule meetings, block focus time, and see your work alongside your events.', 'https://calendar.notion.so', 'free', '[{"plan":"Free","price":0,"period":"month","features":["Full calendar","Notion integration","Meeting links"]}]', 'beginner', false, '{web,desktop,mobile}', '{"Google Calendar sync","Notion integration","Meeting scheduling","Focus time blocks","Meeting notes","Time zones","Multi-calendar","Keyboard shortcuts"}', '{"Notion","Google Calendar","Zoom","Google Meet","Apple Calendar"}', 'https://help.notion.so', true),

('Magical', 'magical', 'AI text expansion and workflow automation', 'Magical is a free Chrome extension that uses AI to auto-fill repetitive data between tabs, expand text shortcuts, and automate data entry. Works on any website without building integrations.', 'https://getmagical.com', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["Unlimited shortcuts","AI message drafting"]},{"plan":"Teams","price":10,"period":"month","features":["Shared templates","Analytics","SSO"]}]', 'beginner', false, '{web}', '{"Text expansion","Auto data transfer","AI drafting","Shortcuts","Template sharing","CRM auto-fill","Works on any site","No integrations needed"}', '{"Chrome","Salesforce","HubSpot","LinkedIn","Gmail","Zendesk"}', 'https://help.getmagical.com', true)

ON CONFLICT (slug) DO NOTHING;

