INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published) VALUES

('Sprout Social', 'sprout-social', 'Social media management with AI-powered insights', 'Sprout Social is a comprehensive social media management platform with AI writing assistance, optimal send times, sentiment analysis, and competitive intelligence for brands and agencies.', 'https://sproutsocial.com', 'paid', '[{"plan":"Standard","price":249,"period":"month","features":["5 profiles","AI assist","Publishing"]},{"plan":"Professional","price":399,"period":"month","features":["Unlimited profiles","AI suggestions"]},{"plan":"Advanced","price":499,"period":"month","features":["AI automation","Advanced analytics"]}]', 'intermediate', true, '{web,mobile,api}', '{"AI content suggestions","Social scheduling","Inbox management","Analytics","Listening","Competitor analysis","Influencer tools","CRM"}', '{"Facebook","Instagram","X/Twitter","LinkedIn","TikTok","Pinterest","Google","Salesforce","HubSpot"}', 'https://developers.sproutsocial.com', true),

('Taplio', 'taplio', 'AI-powered LinkedIn growth tool', 'Taplio helps professionals grow their LinkedIn presence with AI post generation, carousel creation, post scheduling, and analytics. Includes a daily content inspiration feed and relationship management.', 'https://taplio.com', 'paid', '[{"plan":"Starter","price":49,"period":"month","features":["AI generation","Basic scheduling"]},{"plan":"Standard","price":65,"period":"month","features":["Advanced AI","Analytics","Carousel builder"]},{"plan":"Pro","price":199,"period":"month","features":["Team","CRM","API"]}]', 'beginner', false, '{web}', '{"AI LinkedIn posts","Carousel builder","Scheduling","Analytics","Lead finder","DM automation","Content inspiration","Relationship management"}', '{"LinkedIn","Zapier","HubSpot"}', 'https://taplio.com/help', true),

('Tweet Hunter', 'tweet-hunter', 'AI-powered X (Twitter) growth platform', 'Tweet Hunter helps creators and businesses grow on X/Twitter with AI tweet generation, viral thread creation, scheduling, automation, and CRM features to convert followers to customers.', 'https://tweethunter.io', 'paid', '[{"plan":"Starter","price":49,"period":"month","features":["AI tweets","Scheduling","Analytics"]},{"plan":"Growth","price":99,"period":"month","features":["Automation","CRM","Team"]}]', 'beginner', false, '{web}', '{"AI tweet generation","Thread builder","Scheduling","Auto retweet","Auto DM","Analytics","Audience research","Content library","Ghost writer"}', '{"Twitter/X","Zapier","Make","HubSpot"}', 'https://tweethunter.io/blog', true),

('Flick', 'flick', 'AI social media marketing assistant', 'Flick is an AI social media tool that helps create captions, generate content ideas, schedule posts, and research hashtags across Instagram, Facebook, TikTok, and LinkedIn. Ideal for solo creators and agencies.', 'https://flick.social', 'paid', '[{"plan":"Solo","price":14,"period":"month","features":["1 brand","AI writing","Scheduling"]},{"plan":"Growth","price":30,"period":"month","features":["2 brands","Hashtag analytics"]},{"plan":"Pro","price":65,"period":"month","features":["5 brands","AI content planner"]}]', 'beginner', false, '{web,mobile}', '{"AI caption writing","Content ideas","Hashtag research","Scheduling","Analytics","Content calendar","Repurposing","Brand voice"}', '{"Instagram","Facebook","TikTok","LinkedIn","Canva"}', 'https://help.flick.social', true),

('Loomly', 'loomly', 'Brand success platform with AI content suggestions', 'Loomly helps social media managers plan, create, publish, and analyze content across all major platforms. Features AI content suggestions, advanced analytics, ad management, and team collaboration.', 'https://loomly.com', 'paid', '[{"plan":"Base","price":42,"period":"month","features":["2 users","10 calendars","AI assist"]},{"plan":"Standard","price":80,"period":"month","features":["6 users","20 calendars"]},{"plan":"Advanced","price":175,"period":"month","features":["14 users","Unlimited calendars"]}]', 'beginner', false, '{web,mobile}', '{"AI content suggestions","Multi-channel publishing","Content calendar","Analytics","Ad management","Approval workflows","Hashtag suggestions","UTM tracking"}', '{"Facebook","Instagram","X/Twitter","LinkedIn","Pinterest","TikTok","YouTube","Google My Business"}', 'https://help.loomly.com', true)

ON CONFLICT (slug) DO NOTHING;
